// Tally sends { data: { fields: [{label, value}, ...] } }
const fields = $json.body?.data?.fields || [];
const get = (label) => {
  const f = fields.find(f => (f.label || '').toLowerCase().includes(label));
  if (!f) return '';
  return Array.isArray(f.value) ? f.value.join(', ') : (f.value ?? '');
};
return [{
  json: {
    submitted_at: new Date().toISOString(),
    name: get('name'),
    email: get('email'),
    linkedin: get('linkedin'),
    interest: get('bring') || get('interest') || get('why'),
    source: 'tally',
    status: 'new',
    nudge_count: 0,
    last_nudged: ''
  }
}];

